import{_ as o,o as i,c as t,ak as e}from"./chunks/framework.D3PFo-vo.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"chinese/文言字词.md","filePath":"chinese/文言字词.md"}'),r={name:"chinese/文言字词.md"};function a(n,l,s,c,d,g){return i(),t("div",null,[...l[0]||(l[0]=[e('<h2 style="text-align:center;font-size:30px;">文言文</h2><ul><li><h4 id="分值-共20-22分" tabindex="-1">分值：共20-22分 <a class="header-anchor" href="#分值-共20-22分" aria-label="Permalink to &quot;分值：共20-22分&quot;">​</a></h4><ul><li>10.选择题——断句（3分）</li><li>11.选择题——实词虚词文常（3分）【教考衔接】</li><li>12.选择题——文意概括（3分）</li><li>13.主观题——翻译句子，两个（8分）</li><li>14.主观题——概括、分析（3分、5分）【内容概括、理解为主】</li></ul></li></ul><h3 id="文言字词" tabindex="-1">文言字词 <a class="header-anchor" href="#文言字词" aria-label="Permalink to &quot;文言字词&quot;">​</a></h3><ul><li><h4 id="一、文言实词" tabindex="-1">一、文言实词 <a class="header-anchor" href="#一、文言实词" aria-label="Permalink to &quot;一、文言实词&quot;">​</a></h4><ul><li><h5 id="一-文言实词常见的考查内容-详见《复习手册》p206-213" tabindex="-1">（一）文言实词常见的考查内容 （详见《复习手册》P206-213） <a class="header-anchor" href="#一-文言实词常见的考查内容-详见《复习手册》p206-213" aria-label="Permalink to &quot;（一）文言实词常见的考查内容 （详见《复习手册》P206-213）&quot;">​</a></h5><ul><li>1.一词多义</li><li>2.古今异义</li><li>3.通假字</li><li>4.词类活用</li><li>5.偏义复词</li></ul></li><li><h5 id="二-文言实词词义推断的基本方法" tabindex="-1">（二）文言实词词义推断的基本方法 <a class="header-anchor" href="#二-文言实词词义推断的基本方法" aria-label="Permalink to &quot;（二）文言实词词义推断的基本方法&quot;">​</a></h5><ul><li><h6 id="方法一-字形推断词义法" tabindex="-1">方法一：字形推断词义法 <a class="header-anchor" href="#方法一-字形推断词义法" aria-label="Permalink to &quot;方法一：字形推断词义法&quot;">​</a></h6><blockquote><p>汉字造字，有“象形”“指事”“会意”“形声”等方法。汉字大部分为形声字，形旁有表意功能，因此可以从字的形旁来推断词义。</p></blockquote><ul><li>课内实例： <ul><li>（1）引壶觞以自酌，<strong>眄</strong>庭柯以怡颜。（《归去来兮辞》） <code>眄：视，看。</code></li><li>（2）<strong>舳舻</strong>千里（《赤壁赋》） <code>舳舻：船头和船尾，泛指船只。</code></li><li>（3）方其系燕父子以<strong>组</strong>。（《伶官传序》） <code>组：绳索。</code></li></ul></li></ul></li><li><h6 id="方法二-课本迁移法" tabindex="-1">方法二：课本迁移法 <a class="header-anchor" href="#方法二-课本迁移法" aria-label="Permalink to &quot;方法二：课本迁移法&quot;">​</a></h6><blockquote><p>高考文言文所考查的实词，一般秉承“课外材料课内考”的原则，因此，要善于根据课内学过的知识举一反三。</p></blockquote><ul><li>1.俾： <ul><li>（1）宜速召面谕，授敕<strong>俾</strong>行。（2021全国甲卷）</li><li>（2）又嘱学使<strong>俾</strong>入邑庠（蒲松龄《促织》） <code>俾： 使、让</code></li></ul></li><li>2.迨： <ul><li>（1）<strong>迨</strong>其后李广利征匈奴，陵（李陵）将三万余骑追汉军。（2024新课标Ⅰ卷）</li><li>（2）<strong>迨</strong>诸父异爨（《项脊轩志》） <code>迨：等到</code></li></ul></li><li>3.如： <ul><li>郑伯<strong>如</strong>晋，子大叔相，见范献子。（2025全国一卷）</li><li><strong>如</strong>楚，又因厚币用事者臣靳尚。（《屈原列传》） <code>如：到，往。</code></li></ul></li></ul></li><li><h6 id="方法三-语法分析法" tabindex="-1">方法三：语法分析法 <a class="header-anchor" href="#方法三-语法分析法" aria-label="Permalink to &quot;方法三：语法分析法&quot;">​</a></h6><ul><li><strong>句子结构：（定语）主语 [状语] 谓语&lt;补语&gt;（定语）宾语</strong></li></ul><blockquote><p>在汉语语法中，主语、宾语大多是由名词、代词充当，谓语大多由形容词、动词充当，定语由名词、代词充当，状语则由副词充当。因此，可根据词在句中的语法位置来推断它的词性，进而推知它的词义。</p></blockquote><ul><li>（1）魏王<strong>悉</strong>韩、魏之兵，又西借秦兵。（2022新高考Ⅰ卷） <code>悉：动词，倾其全部 </code></li><li>（2）文侯受子夏经艺，<strong>客</strong>段干木，过其闾，未尝不<strong>轼</strong>也。（2024新高考Ⅱ卷） <code>客：动词，以客礼对待</code><code>轼：动词，扶轼表示敬意</code></li><li>（3）昔晋客<strong>舍</strong>吾家，系马园中。（2025全国一卷） <code>舍：动词，寄居</code></li></ul></li><li><h6 id="方法四-结构分析推断法" tabindex="-1">方法四：结构分析推断法 <a class="header-anchor" href="#方法四-结构分析推断法" aria-label="Permalink to &quot;方法四：结构分析推断法&quot;">​</a></h6><blockquote><p>文言文中排比句、对偶句、并列词句等对举的语言现象很多，在这些句子中，位置对称的词语一般词性相同、词义相近或相反，这样通过对已知词语的词性、词义分析，就可以推知未知词语的词性、词义。</p></blockquote><ul><li>（1）并言京（蔡京）欺君僭上、<strong>蠹</strong>国害民数事。（2020新课标Ⅱ卷）<br><code>蠹：蛀蚀，祸害</code></li><li>（2）前代战斗，多是以小术而胜无术，以<strong>片善</strong>而胜无善。（2023新课标Ⅱ卷） <code>片善：微小的优势</code></li><li>（3）<strong>贤</strong>干木（段干木）之操，<strong>高</strong>魏文之礼也。（2024新高考Ⅱ卷） <code>贤：崇尚，以为贤</code><code>高：崇尚，崇敬</code></li><li>（4）今鲁君<strong>老悖</strong>，太子<strong>少愚</strong>，愚伪日起。（2025全国一卷） <code>老悖：年老糊涂</code><code>少愚：年少无知</code></li></ul></li><li><h6 id="方法五-成语印证法" tabindex="-1">方法五：成语印证法 <a class="header-anchor" href="#方法五-成语印证法" aria-label="Permalink to &quot;方法五：成语印证法&quot;">​</a></h6><ul><li>（1）吴汉堕水，<strong>缘</strong>马尾得出。（2022新高考Ⅱ卷） <strong><code>缘：攀援</code></strong> 联想到的成语：<strong><code>缘木求鱼</code></strong><blockquote><p>爬到树上去找鱼。比喻方向、方法不对，一定达不到目的。 （孟子《齐桓晋文之事》：以若所为，求若所欲，犹<strong>缘木而求鱼</strong>也。）</p></blockquote></li><li>（2）军旅<strong>薄</strong>城，吾知子不违也。（2023全国乙卷） <strong><code>薄：靠近、逼近</code></strong> 联想到的成语：<strong><code>日薄西山</code></strong><blockquote><p>太阳快要落山了，比喻衰老的人或腐朽的事物临近死亡。 （李密《陈情表》：但以刘<strong>日薄西山</strong>，气息奄奄。）</p></blockquote></li><li>（3）迁（司马迁）之为陵（李陵）<strong>文</strong>过若不及。（2024新高考Ⅰ卷） <strong><code>文：掩饰</code></strong> 联想到的成语：<strong><code>文过饰非 （掩饰过失、错误 ）</code></strong></li></ul></li><li><h6 id="方法六-语境推断法" tabindex="-1">方法六：语境推断法 <a class="header-anchor" href="#方法六-语境推断法" aria-label="Permalink to &quot;方法六：语境推断法&quot;">​</a></h6><blockquote><p>语境可分为句子<strong>内部语境和外部语境</strong>，所谓内部语境指的是<strong>句子本身的语言环境</strong>，所谓外部语境就是<strong>针对整段文字、整篇文章而言的大语境，即上下文的语言环境</strong>。推断词义的基本原则就是要把词放到句中去理解，根据上下已知条件加以仔细研究，推断出其意义。</p></blockquote><ul><li><p>（1）圣人之于天下百姓也，其犹赤子乎！饥者则<strong>食</strong>之，寒者则<strong>衣</strong>之，将之<strong>养</strong>之，育之长之，唯恐其不至于大也。（2022全国乙卷） <code>食：给吃，喂养</code><code>衣：给衣穿</code><code>将：奉养 （将养：奉养抚育)</code></p></li><li><p>（2）吴汉尝出征，妻子在后买田业。汉还，<strong>让</strong>之。（2022新高考Ⅱ卷） <code>让：责备</code></p></li><li><p>（3）周尧卿居官禄虽薄，<strong>赒</strong>宗族朋友，<strong>罄</strong>而后已。（2023全国甲卷） <code>赒（zhōu）：救济，接济</code><code>罄：尽，用尽</code></p></li><li><p>（4）鲁监门之女婴相从<strong>绩</strong>，中夜而泣涕，其偶曰：“何谓而泣也？ ”（2025全国一卷）（材料四：“遂谓漆室之女不<strong>绩</strong>其麻而忧鲁国”）</p><p><code>绩：绩麻。</code></p></li></ul></li><li><h6 id="方法七-通假字法" tabindex="-1">方法七：通假字法 <a class="header-anchor" href="#方法七-通假字法" aria-label="Permalink to &quot;方法七：通假字法&quot;">​</a></h6><blockquote><p>有时对文言文中某个实词无法理解时，我们可以运用<strong>通假字的字音相近、相同或字形相似</strong>的原则，从通假角度考虑，以另一个可能与之相通的字代入原文来推断词义。</p></blockquote><ul><li>（1）（李陵）常奋不顾身以<strong>徇</strong>国家之急。（2024新高考Ⅰ卷） <code>徇：通“殉”，为某种目的而死。</code></li><li>（2）愿得自当一队，到兰干山南以分单于兵，毋令专<strong>乡</strong>贰师（贰师将军李广利）军。（2024新高考Ⅰ卷） <code>乡：通“向”，面向，朝向。</code></li><li>（3）吾求公数岁，公<strong>辟</strong>逃我。(2024新高考Ⅱ卷) <code>辟：通“避”，躲避。</code></li><li>（4）及<strong>燕</strong>，置酒，太子侍。（2024新高考Ⅱ卷） <code>燕：通“宴”，指宴饮。</code></li></ul></li></ul></li><li><h4 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h4><ul><li>1.文言实词词义的准确推断，往往是几种方法的综合使用。 语法分析定<strong>词性</strong>+<strong>字形</strong>（或课内迁移、通假字、成语联想）+结构分析<strong>对举句式</strong>+<strong>语境</strong></li><li>2.针对教考衔接，<strong>首先应回归教材，夯实基础；其次深入语境，善于迁移。</strong></li><li>3.平日遇到不会的实词，要<strong>有意识综合运用推断方法进行推断，然后查字典进行验证</strong>。</li><li>4.文言实词的积累，不仅需要方法，更需要<strong>记忆</strong>。</li></ul></li></ul></li><li><h4 id="二、文言虚词" tabindex="-1">二、文言虚词 <a class="header-anchor" href="#二、文言虚词" aria-label="Permalink to &quot;二、文言虚词&quot;">​</a></h4><ul><li><h5 id="一-文言虚词常见的考查内容-详见《复习手册》p217-221" tabindex="-1">（一）文言虚词常见的考查内容 （详见《复习手册》P217-221） <a class="header-anchor" href="#一-文言虚词常见的考查内容-详见《复习手册》p217-221" aria-label="Permalink to &quot;（一）文言虚词常见的考查内容  （详见《复习手册》P217-221）&quot;">​</a></h5><ul><li>1.文言代词（人称代词、指示代词、疑问代词等）</li><li>2.文言副词（程度、范围、时间、语气等）</li><li>3.文言连词（并列、递进、选择、承接、转折、因果、假设、修饰等）</li><li>4.文言介词（引出时间、处所、方式、原因、对象等）</li><li>5.文言助词（结构助词、语气助词、音节助词等）</li></ul></li><li><h5 id="二-文言虚词词义推断的基本方法-详见《复习手册》p222-224" tabindex="-1">（二）文言虚词词义推断的基本方法 （详见《复习手册》P222-224） <a class="header-anchor" href="#二-文言虚词词义推断的基本方法-详见《复习手册》p222-224" aria-label="Permalink to &quot;（二）文言虚词词义推断的基本方法 （详见《复习手册》P222-224）&quot;">​</a></h5><ul><li>1.标志识别法</li><li>2.句位分析法</li><li>3.句意推断法</li><li>4.语法分析法</li><li>5.词性界定法</li><li>6.对称分析法</li></ul></li></ul></li><li><h4 id="三、常见句式-详见《复习手册》p225-231" tabindex="-1">三、常见句式（详见《复习手册》P225-231） <a class="header-anchor" href="#三、常见句式-详见《复习手册》p225-231" aria-label="Permalink to &quot;三、常见句式（详见《复习手册》P225-231）&quot;">​</a></h4><ul><li>1.判断句</li><li>2.被动句</li><li>3.省略句</li><li>4.倒装句（宾语前置句、定语后置句、状语后置句、主谓倒装句等）</li><li>5.固定句式</li></ul></li><li><h4 id="四、常见文化词语-详见《复习手册》p232-234" tabindex="-1">四、常见文化词语（详见《复习手册》P232-234） <a class="header-anchor" href="#四、常见文化词语-详见《复习手册》p232-234" aria-label="Permalink to &quot;四、常见文化词语（详见《复习手册》P232-234）&quot;">​</a></h4><ul><li>1.官职沿革类</li><li>2.姓名称谓类</li><li>3.礼仪习俗类</li><li>4.天文地理类</li></ul></li></ul>',4)])])}const b=o(r,[["render",a]]);export{h as __pageData,b as default};
